// // This module implements a 16-bit register that stores the value of the input data on each negative edge of the clock signal only when the enable signal is low.
module register_16bit(
    input wire clk,
    input wire rst,
    input wire en,
    input wire [15:0] data,
    output reg [15:0] q
);

    always @(posedge clk) begin
        if (rst) begin
            q <= 16'b0000000000000000;
        end else if (en) begin
            q <= data;
        end
    end
endmodule
